#include <stdio.h>
int main() {
    int Q;
    scanf("%d", &Q);
    while (Q--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int pos = K;
        for (int k = 0; k < N; k++) {
            if (pos % (1 << (k + 1)) >= (1 << k)) {
                pos = (pos - (1 << k)) + (1 << (k + 1));
            }
        }
        printf("%d\n", pos);
    }
    return 0;
}

