code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int Q = sc.nextInt();
        while (Q-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int pos = K;
            for (int k = 0; k < N; k++) {
                if (pos % (1 << (k + 1)) >= (1 << k)) {
                    pos = (pos - (1 << k)) + (1 << (k + 1));
                }
            }
            System.out.println(pos);
        }
    }
}

